const actionByTopic = {
  'oncovax/demo/control/scenario/select': 'scenario/select',
  'oncovax/demo/control/mode/set': 'mode/set',
  'oncovax/demo/control/event/trigger': 'event/trigger'
};

const incomingTopic = msg.topic;
const action = actionByTopic[incomingTopic] || 'unknown';
let payload = msg.payload;

if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (err) {
    return {
      topic: incomingTopic,
      payload: {
        validation_error: 'payload must be valid JSON object',
        raw_payload: msg.payload
      },
      _meta: { action },
      _controlTopic: incomingTopic
    };
  }
}

if (payload === null || typeof payload !== 'object' || Array.isArray(payload)) {
  return {
    topic: incomingTopic,
    payload: {
      validation_error: 'payload must be an object',
      raw_payload: payload
    },
    _meta: { action },
    _controlTopic: incomingTopic
  };
}

msg.payload = payload;
msg._meta = { action };
msg._controlTopic = incomingTopic;
return msg;

const body = msg.payload || {};
const topic = msg.topic;

const commonRequired = ['contract_version', 'command_id', 'issued_at', 'issued_by'];
const missing = commonRequired.filter((k) => typeof body[k] !== 'string' || body[k].trim() === '');

if (missing.length > 0) {
  msg.validation = {
    ok: false,
    reason: `missing required fields: ${missing.join(', ')}`
  };
  return [null, msg];
}

if (topic === 'oncovax/demo/control/scenario/select' && (typeof body.scenario !== 'string' || body.scenario.trim() === '')) {
  msg.validation = { ok: false, reason: 'scenario must be a non-empty string' };
  return [null, msg];
}

if (topic === 'oncovax/demo/control/mode/set' && typeof body.enabled !== 'boolean') {
  msg.validation = { ok: false, reason: 'enabled must be boolean for mode/set' };
  return [null, msg];
}

if (topic === 'oncovax/demo/control/event/trigger' && (typeof body.event !== 'string' || body.event.trim() === '')) {
  msg.validation = { ok: false, reason: 'event must be a non-empty string for event/trigger' };
  return [null, msg];
}

msg.validation = { ok: true };
return [msg, null];

const payload = msg.payload;
const now = new Date().toISOString();

msg.topic = 'oncovax/demo/orchestration/status';
msg.payload = {
  contract_version: payload.contract_version,
  command_id: payload.command_id,
  status: 'accepted',
  control_topic: msg._controlTopic || 'unknown',
  processed_at: now,
  details: {
    action: msg._meta?.action || 'unknown',
    scenario: payload.scenario,
    enabled: payload.enabled,
    event: payload.event
  }
};

return msg;

const payload = msg.payload || {};
const now = new Date().toISOString();

msg.topic = 'oncovax/demo/orchestration/status';
msg.payload = {
  contract_version: typeof payload.contract_version === 'string' ? payload.contract_version : '1.0',
  command_id: typeof payload.command_id === 'string' ? payload.command_id : 'unknown',
  status: 'rejected',
  control_topic: msg._controlTopic || 'unknown',
  processed_at: now,
  reason: msg.validation?.reason || payload.validation_error || 'invalid command shape',
  details: {
    action: msg._meta?.action || 'unknown'
  }
};

return msg;
